import{_ as i,o as a,c as e,a0 as t}from"./chunks/framework.CEW4uG-d.js";const k=JSON.parse('{"title":"Troubleshooting Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md"}'),o={name:"guide/troubleshooting.md"};function n(l,s,r,h,d,p){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="troubleshooting-guide" tabindex="-1">Troubleshooting Guide <a class="header-anchor" href="#troubleshooting-guide" aria-label="Permalink to &quot;Troubleshooting Guide&quot;">​</a></h1><p>Here are solutions to the most common issues users encounter when using BlockGuard CLI.</p><hr><h2 id="❓-internet-stops-working-after-stopping-blockguard" tabindex="-1">❓ Internet stops working after stopping BlockGuard <a class="header-anchor" href="#❓-internet-stops-working-after-stopping-blockguard" aria-label="Permalink to &quot;❓ Internet stops working after stopping BlockGuard&quot;">​</a></h2><p>This happens if the DNS restoration sequence did not complete cleanly (e.g. BlockGuard crashed or the process was forcefully killed via <code>kill -9</code> without running the <code>stop</code> command).</p><h3 id="linux-fix" tabindex="-1">Linux Fix: <a class="header-anchor" href="#linux-fix" aria-label="Permalink to &quot;Linux Fix:&quot;">​</a></h3><p>Force <code>systemd-resolved</code> to reload DHCP DNS settings from NetworkManager:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemd-resolved</span></span></code></pre></div><p>If that doesn&#39;t work immediately, disconnect and reconnect your Wi-Fi interface, or run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Replace wlo1 with your network interface name</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resolvectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> revert</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlo1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemd-resolved</span></span></code></pre></div><hr><h2 id="❓-blockguard-shows-0-queries-or-does-not-block-ads" tabindex="-1">❓ BlockGuard shows &quot;0 queries&quot; or does not block ads <a class="header-anchor" href="#❓-blockguard-shows-0-queries-or-does-not-block-ads" aria-label="Permalink to &quot;❓ BlockGuard shows &quot;0 queries&quot; or does not block ads&quot;">​</a></h2><p>This means your system&#39;s network DNS is not actually pointing to BlockGuard.</p><h3 id="verify" tabindex="-1">Verify: <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify:&quot;">​</a></h3><p>Check if resolved is routing queries to localhost:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolvectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verify that &quot;DNS Servers: 127.0.0.1&quot; is set on your active interface.</span></span></code></pre></div><h3 id="fix" tabindex="-1">Fix: <a class="header-anchor" href="#fix" aria-label="Permalink to &quot;Fix:&quot;">​</a></h3><p>Restart BlockGuard to force it to re-apply the DNS routing:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><hr><h2 id="❓-permission-denied-when-starting-the-server" tabindex="-1">❓ &quot;permission denied&quot; when starting the server <a class="header-anchor" href="#❓-permission-denied-when-starting-the-server" aria-label="Permalink to &quot;❓ &quot;permission denied&quot; when starting the server&quot;">​</a></h2><p>Ports below <code>1024</code> are system-level privileged ports. DNS runs on port <code>53</code>, which requires administrator access.</p><h3 id="fix-1" tabindex="-1">Fix: <a class="header-anchor" href="#fix-1" aria-label="Permalink to &quot;Fix:&quot;">​</a></h3><p>Always start the daemon with <code>sudo</code> (Linux/macOS) or run Command Prompt as <strong>Administrator</strong> (Windows):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><hr><h2 id="❓-no-active-subscription-found-when-using-sudo" tabindex="-1">❓ &quot;no active subscription found&quot; when using sudo <a class="header-anchor" href="#❓-no-active-subscription-found-when-using-sudo" aria-label="Permalink to &quot;❓ &quot;no active subscription found&quot; when using sudo&quot;">​</a></h2><p>Your license activation details are saved in the user&#39;s home directory (e.g., <code>~/.blockguard/</code>). When you run <code>sudo start</code>, it looks under the root user&#39;s home folder (<code>/root/.blockguard/</code>).</p><h3 id="fix-2" tabindex="-1">Fix: <a class="header-anchor" href="#fix-2" aria-label="Permalink to &quot;Fix:&quot;">​</a></h3><p>Ensure you run the <code>activate</code> command with <code>sudo</code> as well:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> activate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR-LICENSE-KEY</span></span></code></pre></div><hr><h2 id="❓-a-website-or-service-is-broken-falsely-blocked" tabindex="-1">❓ A website or service is broken / falsely blocked <a class="header-anchor" href="#❓-a-website-or-service-is-broken-falsely-blocked" aria-label="Permalink to &quot;❓ A website or service is broken / falsely blocked&quot;">​</a></h2><p>Some blocklists can be aggressive and block legitimate content or login flows.</p><h3 id="fix-3" tabindex="-1">Fix: <a class="header-anchor" href="#fix-3" aria-label="Permalink to &quot;Fix:&quot;">​</a></h3><p>Whitelist the domain to bypass all filters:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whitelist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div>`,37)])])}const u=i(o,[["render",n]]);export{k as __pageData,u as default};
